window.docContents[55].resolve({"/Algebraic-Number-Theory/Dedekind-domains-and-unique-factorisation-of-ideals/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Algebraic-Number-Theory--Dedekind-domains-and-unique-factorisation-of-ideals--Dedekind-Domain":{"contents":"A Dedekind domain is a Noetherian, integrally closed integral domain of Krull dimension at\nmost one — equivalently, in which every nonzero prime ideal is maximal. Such a domain is\ncharacterised by the property that every nonzero ideal factors uniquely as a product of prime\nideals.\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Algebraic Number Theory\u0009Dedekind domains and unique factorisation of ideals","header":"3.2.1. Dedekind Domain","id":"/Algebraic-Number-Theory/Dedekind-domains-and-unique-factorisation-of-ideals/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Algebraic-Number-Theory--Dedekind-domains-and-unique-factorisation-of-ideals--Dedekind-Domain"}});